{
  "model": "{{textToImageModel}}",
  "promptText": "EDITABLE PROMPT: Using the reference image tagged base_image, create a Pixar-like but hyperrealistic high-end 3D animated portrait. Preserve the original person identity, facial structure, skin tone, hair, eyes, expression, pose, clothing, proportions, and overall appearance as much as possible. Apply a subtle Instagram-style beauty retouch filter: reduce facial blemishes, acne, redness, shine, and under-eye shadows while keeping natural skin texture. Use a completely pure white seamless studio background (#FFFFFF). Add soft flattering studio lighting, realistic eyes, detailed hair, natural face shape, and polished cinematic 3D character rendering. Do not change age, ethnicity, face geometry, hairstyle, clothing colors, body shape, or add accessories. Avoid distorted features, heavy makeup, plastic skin, and exaggerated cartoon proportions.",
  "referenceImages": [
    {
      "uri": {{promptImageJson}},
      "tag": "{{referenceImageTag}}"
    }
  ],
  "ratio": "{{textToImageRatio}}"
}
